window.__QUIZ_DATA__=[{"id":"theory>Further Maths>2014>1","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"1","group":"FINAL","topic":"PURE MATHEMATICS : INDICES AND LOGARITHMIC FUNCTIONS","question":"Solve (log2m)2 - Log2m3 = 10     (Leaving the answer in whole number ab)","images":[],"marking_scheme":"Logarithms   (log2m)2 - 3log2m3 = 10     Let; x = log2m     x2 - 3x = 10     x2 - 3x - 10 = 0    x2 + 2x - 5x - 10 = 0     x(x + 2)-5(x + 2) = 0     x + 2 = 0 or x - 5 = 0 ; (x + 2)(x - 5) = 0    x = -2 or 5    \u2192 x = -2  \u2192 x = 5    logm2 = -2     log2m = 5     m = 2  m = 2  m=14  m = 32","marks":"10","difficulty":"3"},{"id":"theory>Further Maths>2014>2>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"FINAL","topic":"PURE MATHEMATICS : BINARY OPERATIONS","question":"A binary operation * is defined on the set of rational numbers by     m * n = m2-n2/2mm , n \u2260 0 and m \u2260 0     Find:    3*2  (Leaving the answer in fraction -a/b)","images":[],"marking_scheme":"m*n=m2-n22mn    (-3*2)=(-3)2-(2)22(-3)(2)=9-4-12=-512","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>2>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"PURE MATHEMATICS : BINARY OPERATIONS","question":"A binary operation * is defined on the set of rational numbers by     m * n = m2-n2/2mm , n \u2260 0 and m \u2260 0     Find:Show whether or not * is associative","images":[],"marking_scheme":"(m*n)*d = m *(n*d)   (m2-n2)/2mn - d2     (m2-n22mn)-d2\u00f72(m2-n22mn)d\u2260m2-(n2-d22nd)\u00f72m(n2-d22nd)    \u2234 LHS \u2260 RHS, the operation under * is not associative","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>3","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"3","group":"FINAL","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"If \u03b1 and \u03b2 are the roots of 3x2 + 5x + 1 = 0,   evaluate 27(\u03b13+\u03b23)      (Leaving the answer in whole number - ab)","images":[],"marking_scheme":"3x2 + 5x + 1 = 0   a = 3, b = 5, c = 1    Root: \u221d and \u03b2     27(\u221d + \u03b2) = ?     Recall,\u221d+\u03b2=-b\u221d=-53    \u221d\u03b2=ca=13    Also, \u221d3+\u03b23 = (\u221d + \u03b2)3 - 3\u221d\u03b2 (\u221d + \u03b2)    \u2234\u221d3+\u03b23=(-53)3-3(13)(-53)    \u221d3+\u03b23=-12527+53    \u221d3+\u03b23=-125+4527    \u221d3+\u03b23=-8027    \u223427(\u221d+\u03b23)=27x-8027=-80","marks":"10","difficulty":"2"},{"id":"theory>Further Maths>2014>4","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"4","group":"FINAL","topic":"PURE MATHEMATICS : DIFFERENTIATION","question":"Find the gradient of xy2 + x2y = 4xy at the point (1, 3)    (Leaving the answer in whole number - ab)","images":[],"marking_scheme":"xy2 + x2y = 4xy   From implicit differentiation   x.2y.dydx+y2+x2.dydx+y.2x=4x.dydx+y.4    2xy.dydx+x2.dydx-4x.dydx=4y-y2-2xy    dy/dx (2xy + x2 - 4x) = 4y - y2 - 2xy     dydx=4y-y2-2xy2xy+x2-4x    dydx=4(3)-32-2(1)(3)2(1)(3)+12-4(1)=12-9-66+1-4=-33=-1","marks":"10","difficulty":"3"},{"id":"theory>Further Maths>2014>5>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"VECTORS AND MECHANICS : VECTORS","question":"The position vectors of points P, Q and R are 11i + j, 5i = 13/3j and 2i + 6j respectively.   Show that P, Q and R lie on a straight line.","images":[],"marking_scheme":"Given;p=i+j,q=5i+133j,r=2i+6j    GradientPQ=y2-y1x2-x1=133-1\u00f75-11=103\u00f7-6=103x-16=-1018=-59    GradientPR=y3-y2x3-x2=6-133\u00f72-5=53\u00f7-3=53x-13=-59    Since Gradients PQ = PR   \u2234 The vector all lie on a straight line","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>5>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"FINAL","topic":"VECTORS AND MECHANICS : VECTORS","question":"Find the ratio of | PQ | : | QR |    (Leaving the answer in ratio  b:a)","images":[],"marking_scheme":"| PQ | : | QR | = ?     Recall,PQ=\u221a(-6)2+(103)2=\u221a36+1009=2\u221a1063    QR=\u221a(3)2+(53)2=\u221a9+259=\u221a1063    \u2234PQ:QR=2\u221a1063:\u221a1063    =2\u221a1063x3\u221a106=21    \u2234| PQ | : | QR | = 2:1","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>6>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"FINAL","topic":"PURE MATHEMATICS : PERMUTATION AND COMBINATIONS.","question":"A committee of 3 is formed from a panel of 5 men and 3 women. Find the:    number of ways of forming the committee    (Leaving the answer in whole number  ab)","images":[],"marking_scheme":"rT = 3, nm = 5 , nw = 3, nT = 5+3 = 8     No. of ways of forming committee = 8C3    =8!5!3!=8x7x6x5!5!x3x2=56","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>6>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"FINAL","topic":"STATISTICS AND PROBABILITY : PROBABILITY","question":"A committee of 3 is formed from a panel of 5 men and 3 women. Find the:probability that at least one woman is on the committee    (Leaving the answer in fraction b/a)","images":[],"marking_scheme":"Pr(rw\u22651)=1-(5C3x3C6)8C3    =1-(10x1)56=1-1056=4656    =2328","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>7","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"7","group":"FINAL","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"The table shows the distribution of the length of 20 iron rods measured in metres.   Lenght (m) 1.0-1.1 1.2-1.31.4-1.5 1.6-1.71.8-1.9Frequency 2 3 8 5 2    Using an assured men of 1.45, calculate the mean of the distribution.     (Leaving the answer in two decimal places a.bc)","images":[],"marking_scheme":"length x  f  d = x - A fd1.0-1.1 1.05 2 -0.4 -0.81.2-1.3 1.25 3 -0.2 -0.61.4-1.5 1.45 8 0.0 0.01.6-1.7 1.65 5 0.2 1.11.8-1.9 1.85 2 0.4 0.8   20  0.4    Recall,meanx=\u2211fd\u2211f+A    x=0.420+1.45=0.02+1.45     x  = 1.47","marks":"10","difficulty":"3"},{"id":"theory>Further Maths>2014>8","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"8","group":"","topic":"VECTORS AND MECHANICS : STATICS","question":"Find the direction of the resultant of the forces in the diagram.","images":["data:image/png;base64,"],"marking_scheme":"R =    8\u221a2Sin4508\u221a2Cos45+20Sin120020Cos1202      10Sin330010Cos3300=-7-0.66    tan\u03b8=-0.66-7,tan\u03b8=0.0943    \u03b8 = tan-1(0.0943)    \u03b8 = 5.390    \u03b8 = 2650 or 584.610 W","marks":"10","difficulty":"3"},{"id":"theory>Further Maths>2014>9>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"PURE MATHEMATICS : DIFFERENTIATION","question":"Differentiate (x - 3)(x2 + 5) with respect to x.","images":[],"marking_scheme":"y = (x - 3)(x2 + 5)    Let; u = x - 3, v = x2 + 5     dudx=1;dvdx=2x    \u2234dydx=v.dudx+u.dvdx=(x2+5)(1)+(x-3)(2x)    dydx=x2+5+2x2-6x:y1=3x2-6x+5","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>9>b>i","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"i","group":"","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"If (x + 1)2 is a factor of  f (x) = x3 + ax2 + bx + 3, where a and b are constant, find the:   values of a and b","images":[],"marking_scheme":"(x + 1)2 \u2192 Factor of f(x) = x2 + ax2 + bx + 3  a, b = ?   f(x) = x3 + ax2 + bx + 3   (x + 1)2 - factor     x2 + 2x + 1  Since (x + 1)2 is a factor     (x2 + 2x + 1)(cx + d) = f(x)    cx3 + (2c + d)x2 + (c + 2d)x + d = f(x)    Comparing co-efficients;   \u2192 c = 1  \u2192  2c + d = a \u2192 2d + c = b     \u2234 2d + 1 = b     2(1) + d = a     d = -3 , a = 5, b = 7","marks":"3","difficulty":"3"},{"id":"theory>Further Maths>2014>9>b>ii","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"ii","group":"","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"zeros of  f (x)","images":[],"marking_scheme":"f(x) = x3 = x3 + 5x2 + 7x + 3     f(x) = (x + 1)2(x + 3)     \u2234 Since (x + 1), (x + 1) and (x + 3) are all factors;   then; x + 1 = 0 , x = -1   x + 1 = 0 , x = -1   x + 3 = 0, x = -3     \u2234 Zero's of f(x) are -1, -1 and -3","marks":"2","difficulty":"2"},{"id":"theory>Further Maths>2014>10>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"PURE MATHEMATICS : SURDS","question":"Express5+\u221a23-\u221a2-5-\u221a23+\u221a2intheforma+b\u221a2","images":[],"marking_scheme":"5 + \u221a2/3-\u221a2 - 5-\u221a2/3+\u221a2 in the form 'a+b\u221a2    (3+\u221a2)(5+\u221a2)-(5-\u221a2)(3-\u221a2)/(3-\u221a2)(3+\u221a2)     = 15+3\u221a2+5\u221a2+2-(15-5\u221a2-3\u221a2+2)/32-\u221a2     =15-15+3\u221a2+8\u221a29-2=16\u221a27","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>10>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"FINAL","topic":"PURE MATHEMATICS : MATRICES AND DETERMINANTS","question":"Solve the following equations simultaneously using the determinant method:    3x - y - z = -2   X + 5y + 2z = 5  2x + 3y + z = 0    (Leaving the answer in whole number b)","images":[],"marking_scheme":"\u2206=3-1-1152231    =+3(5-6)+1(1-4)-1(3-10)  =3(-1)+1(-3)-1(-7)    \u2206 = -3-3+7 = 1    \u2206x=-2-1-1552031    =-2(5-6)+1(5-0)-1(15-0)  =2+5-15=-8    \u2206y=1522013-1-2    +1(0+1) -5(-4-3)+2(-2-0)  =1(1)-5(-7)+2(-2)  =1+35-4=19    \u2206z=3-1-2155236  =   +3(30 - 15) +1 (6 - 10) -2(3 - 10)    =3(15)+1(-4)-2(-7)=45-4+14=-41","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>11>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"PURE MATHEMATICS : FUNCTIONS","question":"If f (x)=x - 32x - 1,x\u226012and g (x)=x - 1x + 1,x\u2260-1,find g   of","images":[],"marking_scheme":"f(x) = x-3/2x-1 , g(x) = x-1/x+1 ; g o f     g . f = g(f(x)) = ?     g.f=(x-32x-1)-1\u00f7(x-32x-1)+1=x-3-(2x-1)2x-1\u00f7x-3+(2x-1)2x-1    =x-3-2x+12x-1x2x-1x-3+2x-1=-x-23x-4","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>11>b>i","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"PURE MATHEMATICS : POLYNOMIAL FUNCTIONS","question":"Sketch the curve y = 9x - x3","images":["data:image/png;base64,"],"marking_scheme":"Let y = 9x - x2    when y = 0, 9x - x3 = 0     x(32 - x2) = 0     x (3 - x)(3 + x) = 0    \u2234 x = 0 or 3-x = 0 or 3+x = 0   x = 0 or -3 or 3     Pointofinflexion;d2ydx2=-6x","marks":"3","difficulty":"3"},{"id":"theory>Further Maths>2014>11>b>ii","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"ii","group":"FINAL","topic":"PURE MATHEMATICS : FUNCTIONS","question":"Calculate the total area bounded by the x-axis and the curve y = 9x - x3    (Leaving the answer in one decimal place)","images":[],"marking_scheme":"Total Area = \u222b30 (9x - x3) d x   \u222b-30 (9x - x3)dx     \u222b(9x - x3)dx = \u222b9x - dx     =9x22-x44+C    =(9x22-x44)30-(9x2-x44)0-3    =814+814=812,squareunits.    =40.5sq.units","marks":"2","difficulty":"2"},{"id":"theory>Further Maths>2014>12>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"The histogram above represents the scores of some candidates in an examination.     Using the histogram construct a frequency distribution table indicating clearly the class intervals.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"","marks":"5","difficulty":"1"},{"id":"theory>Further Maths>2014>12>b>i","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"The histogram above represents the scores of some candidates in an examination.   Using the histogram construct a frequency distribution table indicating clearly the class intervals. Draw a cumulative frequency curve of the distribution and use it to estimate the:    - median    (Leaving the answer in one decimal place)","images":["data:image/png;base64,"],"marking_scheme":"Median = 47.5  +  0.5","marks":"3","difficulty":"2"},{"id":"theory>Further Maths>2014>12>b>ii","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATISTICS AND PROBABILITY : STATISTICS","question":"The histogram above represents the scores of some candidates in an examination.   Using the histogram construct a frequency distribution table indicating clearly the class intervals. Draw a cumulative frequency curve of the distribution and use it to estimate the:   Quartile deviation     (Leaving the answer in whole number bc)","images":["data:image/png;base64,"],"marking_scheme":"Upper Quartile = 57.5  +  0.5   Lower quartile = 34.5  +  0.5     Quartile deviation = 57.5 - 34.5 = 23 = 23  +  0.5","marks":"2","difficulty":"2"},{"id":"theory>Further Maths>2014>13>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"FINAL","topic":"STATISTICS AND PROBABILITY : PROBABILITY","question":"The probabilities that Kofi, kwasi and Ama will pass a certain examination are 9/10 , E and a respectively.   If the probability that only one of them will pass examination is 9/50 , find the:    value of x    (Leaving the answer in fraction q/p)","images":[],"marking_scheme":"Pr(Ko) = Pr(Kofi pass) = 9/10     Pr(kw) = Pr(kwasi pass) = 4/5     Pr(A) = Pr(Ama pass) = a    Pr(pass = 1 only) = Pr(Ko kw 'A') + Pr(Ko 'kw A') + Pr(Ko'Kw' A)    950=(910x15x(1-a))+(110x45x(1-a))+(110x15xa)    950=9-9a50+4-4a50+a50    950=(9-9a)+(4-4a)+a50    9 = 9 - 9a + 4 - 4a + a     -12a = 9 - 9 - 4    -12a=-4;a=-4-12    a=13","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>13>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"FINAL","topic":"STATISTICS AND PROBABILITY : PROBABILITY","question":"The probabilities that Kofi, kwasi and Ama will pass a certain examination are 9/10 , E and a respectively.   If the probability that only one of them will pass examination is 9/50 , find the: probability that at least one of them will pass examination    (Leaving the answer in three decimal places)","images":[],"marking_scheme":"Pr. (at least one pass) = Pr(pass \u2265 1)    Pr (Pass \u2265 1) = 1 - Pr (all fail)= 1 - Pr(ko 'kw'A')    =1-(110x15x(1-13))=1-(110x15x23)    =1-2150=148150=7475=0.987","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>14>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"","topic":"VECTORS AND MECHANICS : VECTORS","question":"Giventhatx=3i - j,y=2i+kjandthecosineoftheanglebetweenxandyis\u221a55,  find the values of the constant k.","images":[],"marking_scheme":"InQuadrilateralABCD,AB=(51),AC=(-6-9),BD=(4-7)    Recall, Cos \u03b8 = x.y/|x|.|y|    Cos\u03b8=(3i-5)(2i+kj)\u221a32+(-1)2\u221a22+k2=6-k\u221a10\u221a4+k2    Also,Cos\u03b8=\u221a155    \u22346-k\u221a10(\u221a4+k2)=\u221a155;5(6-k)=\u221a150(\u221a4+k2)    (30 - 5k)2 = \u221a200 + 50k2    25k2 + 300k - 700 = 0     Divide through by 25    k2 + 14k - 2k - 28 = 0   ; k(k + 14) -2(k + 14) = 0     (k + 14)(k - 2) = 0     k + 14 = 0 or k - 2 = 0     k = -14 or 2","marks":"5","difficulty":"3"},{"id":"theory>Further Maths>2014>14>b","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"b","group":"","topic":"PURE MATHEMATICS : CO-ORDINATE GEOMETRY OF STRAIGHT LINES","question":"In the quadrilateral ABCD.     AB=5-1,AC=-6-9andBD=4-7    Show whether or not ABCD is a parrallelogram.","images":["data:image/png;base64,"],"marking_scheme":"BC=AC-AB=-69--5-1=-1-8    CD=BD-BC=4-7--1-8=51    \u2234AB=-5-1      AB // BC     AD=-6-9+51=-1-8    AD//BC and |AD| = |BC|    \u2234 ABC is a parallelogram","marks":"5","difficulty":"2"},{"id":"theory>Further Maths>2014>15>a","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"a","group":"FINAL","topic":"VECTORS AND MECHANICS : VECTORS","question":"A(-1, 2), B(3, 5) and C(4, 8) are the vertices of triangle ABC. Forces whose magnitudes are 5N and 3\u221a10N act along AB and GB respectively. Find the direction of the resultant of the forces.     (Leaving the answer in whole number abc)","images":["data:image/png;base64,"],"marking_scheme":"AB=b-a=35--12=43    CB=35-48=-1-3    AB=1543.5=43    CB=1\u221a10.-1-3.3\u221a10=5-1-3=-3-9    R=43+-3-9SinceR=CB+AB    R=1-6    Alsotan\u03b8=-61    \u03b8=tan-1-61    \u03b8 = 80.530    Actual angle = 900 + 80.530 = 170.530 \u2243 1710","marks":"1","difficulty":"3"},{"id":"theory>Further Maths>2014>15>b>i","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"i","group":"FINAL","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A particle starts from rest and moves in a straight line. It contains a velocity of 20 ms-1 after covering a distance of 8 metres. Calculate:    its acceleration;     (Leaving the answer in whole number bc)","images":[],"marking_scheme":"Recall, v2 = u2 + 2as     (204)2=02+2a(12)    52 = 0 + a     a = 25ms-2","marks":"3","difficulty":"2"},{"id":"theory>Further Maths>2014>15>b>ii","subject":"Further Maths","year":"2014","type":"Theory","sub_label":"ii","group":"FINAL","topic":"VECTORS AND MECHANICS : THE CONCEPTS OF MOTION","question":"A particle starts from rest and moves in a straight line. It contains a velocity of 20 ms-1 after covering a distance of 8 metres. Calculate:the time it will take to cover a distance of 40 metres.     (Leaving the answer in one decimal place)","images":[],"marking_scheme":"Also,S=ut+12at2    t = ? , S = 40m, u = 0ms-1, a = 25ms-2     40=0(t)+12(25)t2    40=252t2;80=25t2    t2=8025;t2=165    t=\u221a165    t = 1.8s","marks":"2","difficulty":"2"}];